import { ethers } from "ethers";

const RPC_URL = process.env.ETH_RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID";
const PRIVATE_KEY = process.env.ETH_PRIVATE_KEY || "YOUR_PRIVATE_KEY";

if (!PRIVATE_KEY || PRIVATE_KEY === "YOUR_PRIVATE_KEY") {
  throw new Error("Missing ETH_PRIVATE_KEY environment variable");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

export function getWalletAddress() {
  return wallet.address;
}

export async function getEthBalance(address = wallet.address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

export async function sendEth(to, amountInEth, options = {}) {
  if (!ethers.isAddress(to)) {
    throw new Error("Invalid recipient address");
  }

  const tx = {
    to,
    value: ethers.parseEther(String(amountInEth)),
    gasLimit: options.gasLimit ? BigInt(options.gasLimit) : undefined,
    gasPrice: options.gasPriceGwei ? ethers.parseUnits(String(options.gasPriceGwei), "gwei") : undefined,
    nonce: options.nonce,
  };

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait(options.confirmations ?? 1);

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    gasLimit: response.gasLimit?.toString(),
    receipt,
  };
}

export function getContract(contractAddress, abi, signerOrProvider = wallet) {
  if (!ethers.isAddress(contractAddress)) {
    throw new Error("Invalid contract address");
  }
  return new ethers.Contract(contractAddress, abi, signerOrProvider);
}

export async function callContractRead(contractAddress, abi, methodName, args = []) {
  const contract = getContract(contractAddress, abi, provider);
  if (typeof contract[methodName] !== "function") {
    throw new Error(`Method ${methodName} not found on contract`);
  }
  return await contract[methodName](...args);
}

export async function sendContractTransaction(contractAddress, abi, methodName, args = [], options = {}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (typeof contract[methodName] !== "function") {
    throw new Error(`Method ${methodName} not found on contract`);
  }

  const overrides = {};
  if (options.valueEth !== undefined) {
    overrides.value = ethers.parseEther(String(options.valueEth));
  }
  if (options.gasLimit !== undefined) {
    overrides.gasLimit = BigInt(options.gasLimit);
  }
  if (options.gasPriceGwei !== undefined) {
    overrides.gasPrice = ethers.parseUnits(String(options.gasPriceGwei), "gwei");
  }
  if (options.nonce !== undefined) {
    overrides.nonce = options.nonce;
  }

  const txResponse = await contract[methodName](...args, overrides);
  const receipt = await txResponse.wait(options.confirmations ?? 1);

  return {
    hash: txResponse.hash,
    from: txResponse.from,
    to: txResponse.to,
    nonce: txResponse.nonce,
    receipt,
  };
}

export async function estimateEthTransferGas(to, amountInEth) {
  const gas = await provider.estimateGas({
    from: wallet.address,
    to,
    value: ethers.parseEther(String(amountInEth)),
  });
  return gas.toString();
}

export async function estimateContractGas(contractAddress, abi, methodName, args = [], options = {}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (!contract[methodName] || !contract[methodName].estimateGas) {
    throw new Error(`Method ${methodName} not found or cannot estimate gas`);
  }

  const overrides = {};
  if (options.valueEth !== undefined) {
    overrides.value = ethers.parseEther(String(options.valueEth));
  }

  const gasEstimate = await contract[methodName].estimateGas(...args, overrides);
  return gasEstimate.toString();
}

export async function getTransaction(txHash) {
  return await provider.getTransaction(txHash);
}

export async function getTransactionReceipt(txHash) {
  return await provider.getTransactionReceipt(txHash);
}

export async function getNetwork() {
  return await provider.getNetwork();
}

export async function getNonce(address = wallet.address, blockTag = "pending") {
  return await provider.getTransactionCount(address, blockTag);
}

export async function getFeeData() {
  const feeData = await provider.getFeeData();
  return {
    gasPrice: feeData.gasPrice?.toString() ?? null,
    maxFeePerGas: feeData.maxFeePerGas?.toString() ?? null,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas?.toString() ?? null,
  };
}

export default {
  provider,
  wallet,
  getWalletAddress,
  getEthBalance,
  sendEth,
  getContract,
  callContractRead,
  sendContractTransaction,
  estimateEthTransferGas,
  estimateContractGas,
  getTransaction,
  getTransactionReceipt,
  getNetwork,
  getNonce,
  getFeeData,
};